using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using BenchmarkDotNet.Toolchains.CsProj;
using TextAnalysis;

var config = DefaultConfig.Instance
    .AddJob(Job.Default.WithToolchain(CsProjCoreToolchain.NetCoreApp90).WithId("net9.0"))
    .AddJob(Job.Default.WithToolchain(CsProjCoreToolchain.NetCoreApp10_0).WithId("net10.0"));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config, args);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    private const string SampleText =
        "The quick brown fox jumps over the lazy dog " +
        "A stitch in time saves nine and the early bird catches the worm " +
        "To be or not to be that is the question whether it is nobler in the mind " +
        "All that glitters is not gold not all those who wander are lost " +
        "It was the best of times it was the worst of times it was the age of wisdom " +
        "The only thing we have to fear is fear itself so let us move forward together " +
        "In the beginning was the word and the word was with God and the word was God " +
        "Four score and seven years ago our fathers brought forth on this continent a new nation";

    [GlobalSetup]
    public void Setup()
    {
        _analyzer = new TextAnalyzer(SampleText);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

